var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"크읏…!!","JPN":"くうっ……！！","ENG":"Krgh...!!","TWN":"咳呃…！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"저 사람. 톱만 휘두를 뿐인데 드레카바크보다 강해.","JPN":"あの人、ノコギリを振り回してるだけなのにドレカバクより強い。","ENG":"That one... She's only swinging a saw, yet she's stronger than Drekavac.","TWN":"那個人明明只是揮舞鋸子，卻比德蕾卡娃克還強。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"근접 전투는 승산이 없어…!!","JPN":"近接戦では勝てない……！！","ENG":"There's no winning at close range...!!","TWN":"近距離戰鬥毫無勝算…！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"음… 먼저 공격해와서 나도 모르게 반격하긴 했는데.","JPN":"うん……攻撃してくるからつい反撃しちゃったけど。","ENG":"Hmm... She struck first, so I reflexively countered.","TWN":"嗯…因為她先發動攻擊，我就不自覺地反擊了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"생각해보니 괜찮은가? 상황만 보면 내가 악당이잖아.","JPN":"よく考えたらこれ大丈夫かな？　この状況じゃ私が悪者じゃない。","ENG":"On second thought, is that okay? From the looks of it, I'm the villain here.","TWN":"但想想發現還不錯？單看情況的話，我就是個壞蛋。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨도 부재중이니, 공인 카운터가 여기서 사고치면 곤란해.","JPN":"ジャクソンさんもいないのに、公認カウンターがここで問題を起こしたらまずいよね。","ENG":"With Mr. Jackson absent, it would be bad if an Official Counter caused a scene here.","TWN":"傑森也不在，要是公認制裁者在這裡闖禍就麻煩了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"적당히 죽은 척하고 타이밍 봐서 빠져나갈까? 목만 따로 어디 파묻지는 않겠지?","JPN":"適当に死んだふりをして、隙を狙って逃げる？　まさか首だけどっかに埋めたりしないよね？","ENG":"Should I play dead and slip out when I get a chance? They won't lop off my head and bury it somewhere, right?","TWN":"適當地裝死，然後找時機脫逃吧？應該不會只把脖子另外埋在哪裡吧？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"머리 좋은 로터스 깡패라면, 이럴 때…….","JPN":"頭のいいロータスのごろつきなら、こんな時……","ENG":"If it were that brainy Lotus gangster, at a time like this...","TWN":"如果是聰明的洛德斯流氓，這種時候……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시로코바. 잘 들으시죠.","JPN":"シロコバ、よく聞いてください。","ENG":"Shirokova. Listen carefully.","TWN":"西羅克巴，請妳聽清楚。"},"stage":{"bg":"ROOM_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"애초에 문제 생길 일을 저지르지 마십시오.","JPN":"そもそも問題が起こりそうなことに首をつっこまないことです。","ENG":"Do not do anything that will cause problems in the first place.","TWN":"不要做出會有問題的事。"},"stage":{"bg":"ROOM_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이씨…!","JPN":"ああもう……！","ENG":"Ugh...!","TWN":"該死…！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"야, 관음증 변태! 예지 능력으로 이 정도 미래는 봤을 거 아니야? 어떻게 좀 해봐!","JPN":"ちょっと、覗き魔！　予知能力でこの辺の未来は見たんでしょ？　なんとかしてよ！","ENG":"Hey, you voyeur creep! With your foresight you saw this coming, right? Do something!","TWN":"喂，偷窺變態！妳的預知能力應該能看到這點未來吧？想想辦法！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"짐승 상대하는 것도 벅찬데, 하긴 뭘 해?","JPN":"獣の相手だけでも精一杯なのに、なんとかって何よ！","ENG":"I'm barely keeping up with this beast! What do you expect me to do?!","TWN":"對付禽獸就已經很吃力了，還要做什麼？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"오히려 S급 카운터는 너잖아! 저깟 인형은 날려버린 뒤에 날 도우라고!","JPN":"そっちはS級カウンターでしょ！　あんな人形早くぶっ飛ばしてこっちに加勢しなさいよ！","ENG":"You're the Grade S Counter here. Take out that doll and then help me!","TWN":"反倒是妳這個S級制裁者！把那區區玩偶消滅之後來幫我！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"웃긴다. 네 개인사를 왜 내가 수습해?","JPN":"はあ？　あなたの個人的な事情に何で私が手を貸す必要があるの？","ENG":"Funny. Why should I clean up your personal mess?","TWN":"真可笑，我為什麼要收拾妳的私事？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래. 그럴 줄 알았다!","JPN":"そう言うと思ったわ！","ENG":"Yeah. I figured you'd say that!","TWN":"是啊，我就知道會這樣！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"한 가지 묻고 싶은 게 있어.","JPN":"1つ聞きたいことがある。","ENG":"I have one question for you.","TWN":"我想問一件事。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"당신은 어째서 북방합의체를 돕는 거지?","JPN":"あなたはどうして北方合意体に協力してるの？","ENG":"Why are you helping the Northern Union?","TWN":"妳為什麼要幫北方和議會？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"그 녀석들이 어떤 짓을 저지르는지 모르는 거야?","JPN":"あいつらが何をしているのか、知らないの？","ENG":"Don't you know what they have done?","TWN":"妳不知道那些傢伙在做什麼事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"글쎄요? 세상 누구보다 제가 제일 잘 알 걸요?","JPN":"さあ？　たぶん私が誰よりもよく知ってると思いますけど？","ENG":"Oh, I do. Better than anyone, actually.","TWN":"這個嘛？我應該比這世上任何人都還了解吧？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저도 북방합의체 실험의 피해자거든요.","JPN":"私も北方合意体の実験の被害者だから。","ENG":"I'm also a victim of Northern Union experiments.","TWN":"因為我也是北方和議會實驗的受害者。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"그렇다면 어째서…!","JPN":"なら、どうして……！","ENG":"Then why...?!","TWN":"那妳為什麼…！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"간단해요. 절 실험실에서 꺼내 준 은인이 있거든요.","JPN":"簡単です。私を実験室から連れ出してくれた恩人がいるんです。","ENG":"Simple. Someone pulled me out of that lab.","TWN":"很簡單，因為有個把我從實驗室救出去的恩人。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"한 번 도움을 받아 놓고, 모른척할 게 아닌 이상…….","JPN":"助けてもらっておいて、知らんぷりだなんてしたくはないし……","ENG":"After receiving help once, I can't just turn a blind eye...","TWN":"既然得到一次幫助，就不該裝作不知道……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이렇게나 도움을 받아놓고, 모른체 할 순 없잖아?","JPN":"こんなに助けてもらって、何もせずにはいられないでしょう？","ENG":"So I can't just turn a blind eye when I've received this much help, right?","TWN":"得到這樣的幫助之後，總不能裝作不知道吧？"},"stage":{"bg":"DORMITORY_3","bgm":"BATTLE_NORMAL_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마을을 위해 무언가 할 수 있는 게 있다면 보답을 해주고 싶어.","JPN":"村のために何かできることがあるなら、私は恩返しがしたい。","ENG":"I want to repay by doing whatever I can for the village.","TWN":"如果能為村子做些什麼，我想報答。"},"stage":{"bg":"DORMITORY_3","bgm":"BATTLE_NORMAL_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 그 사람을 위해 할 수 있는 일을 할 뿐이에요.","JPN":"私はあの人のためにできることをするだけです。","ENG":"I'm simply doing what I can for that person.","TWN":"我只是為了那個人做自己能做的事而已。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐, 당신은 이해 못하겠지만.","JPN":"ま、あなたには理解できないでしょうけど。","ENG":"Not that you would understand.","TWN":"嗯，雖然妳應該無法理解。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"아니, 이해해. 그 마음.","JPN":"いや、理解できるよ。その気持ち。","ENG":"No, I do understand.","TWN":"不，我理解那種心情。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"하지만, 이쪽도 물러설 순 없어…!!","JPN":"でも、私も引き下がることはできない……！！","ENG":"But I can't back down either...!!","TWN":"但是我也無法退縮…！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"마트료시카 인형이 카운터 워치를 사용한다고?","JPN":"マトリョシカ人形がカウンターウォッチを使ってる？","ENG":"A Matryoshka doll using a Counter Watch?","TWN":"俄羅斯娃娃使用制裁者能量環？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG_02"},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"야, 전라광! 괜히 이상한 생각 말고 피해!","JPN":"待って、露出狂！　余計なこと考えてないで避けなさい！","ENG":"Hey, streaker princess! Quit the weird ideas and evade!","TWN":"喂，妳這瘋子！不要有奇怪的念頭，快躲開！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐래. 내가 재생만 할 줄 아는 샌드백인 줄 알아?","JPN":"私のこと再生しかできないサンドバックだと思ってるの？","ENG":"Excuse you. You think I'm just a regenerating punching bag?","TWN":"妳在說什麼？妳以為我是只懂得再生的沙包嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"공인 S급의 저력을 보여줄 테니까, 거기서 구경이나 해.","JPN":"公認S級カウンターの底力を見せてあげるから、そこで指くわえて見てなさい。","ENG":"I'll show you what an Official Grade S Counter can do, so watch from there.","TWN":"我會讓妳見識公認S級的實力，妳就在那裡看著吧。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"아니, 그게 아니라…….","JPN":"いや、そうじゃなくて……","ENG":"No, that's not it...","TWN":"不，不是那樣的……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"니들이 날뛰면 건물이 무너진다고, 이 멍청이들아!!","JPN":"お前たちが暴れたら建物が崩壊するのよ、このバカども！！","ENG":"If you run wild, the building will collapse, you idiots!","TWN":"要是妳們鬧得雞飛狗跳，建築會倒塌，妳們這些笨蛋！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"잡았다, 요놈.","JPN":"捕まえたぞ。","ENG":"Got you, brat.","TWN":"抓到妳這傢伙了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"}}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"지, 지금 그게 중요해? 건물이 무너지기 전에 도망쳐야 한다고!","JPN":"い、今はそれどころじゃないのよ！　建物が崩壊する前に逃げないと！","ENG":"I-is that what matters now? We need to run before the building crumbles!","TWN":"現、現在那個重要嗎？我們要在建築倒塌之前逃跑！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"글쎄. 그건 제자 후보가 어련히 알아서 하겠지.","JPN":"さあ、それは弟子候補がなんとかするじゃろう。","ENG":"I doubt it. My apprentice candidate will handle that just fine.","TWN":"這個嘛，徒弟候選人肯定會自己看著辦。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당초 힘에 취해 상황을 구분 못 할 꼬맹이였다면 대장장이의 길을 권하지도 않았다.","JPN":"そもそも、力に酔って状況判断もできない若造だったら、鍛冶屋など勧めておらん。","ENG":"If she were a kid drunk on power who could not read a situation, I would not have recommended the path of a blacksmith.","TWN":"如果她當初是個沉醉於力量，搞不清楚狀況的小毛頭，我也不會建議她走鐵匠這條路。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"저 인형. 누가 봐도 꼬맹이잖아, 이 늙다리야…!!","JPN":"あの人形、どこから見てもガキじゃない。このババア……！！","ENG":"That doll is a kid to anyone's eyes, you old hag...!!","TWN":"那個玩偶，任誰來看都是小毛頭啊，妳這個老人…！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"}}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"무장 구축. 에너지 풀파워.","JPN":"武装構築。エネルギーフルパワー。","ENG":"Armament configuration. Energy at full power.","TWN":"構建武裝，能量充斥。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"스푸트니크 사샤…!!","JPN":"スプートニク・サシャ……！！","ENG":"Sputnik Sasha...!!","TWN":"摯友莎夏…！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_GRAYSTATION_SKILL_LOOP"},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"아, 안 돼.","JPN":"だ、だめ。","ENG":"N-no.","TWN":"不、不行。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"무너진다아아아…….","JPN":"壊れるぅぅぅ……","ENG":"It's going to collapse...","TWN":"會倒塌啊啊啊……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"어라? 안 무너졌잖아?","JPN":"あれ？　壊れてない？","ENG":"Huh? It didn't collapse.","TWN":"咦？沒有倒塌啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당했다. 처음부터 정면승부 할 생각은 없었네.","JPN":"やられた。最初から真剣勝負するつもりなんかなかったのか。","ENG":"We've been made. They never planned for a fair fight.","TWN":"被耍了，看來妳從一開始就不打算正面對決。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"건물벽을 날려 버리다니, 머리 좀 썼는 걸?","JPN":"壁をぶっ壊すなんて考えたね。","ENG":"Blowing out the wall to the outside... That's smart.","TWN":"居然把建築的牆壁弄垮，動了點腦筋啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"그래. 구태여 유리한 상황을 배제하고 싸울 필요는 없지.","JPN":"ああ。事を有利に進められる状況を排除して、あえて戦う必要はないからな。","ENG":"Yeah. There's no need to throw away an advantage.","TWN":"沒錯，沒必要硬是排除有利的情況去戰鬥。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L1_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"고생했다, 마브카. 이제 우리에게 맡기도록.","JPN":"ご苦労だった、マブカ。後は私たちに任せろ。","ENG":"Good work, Mavka. Leave it to us now.","TWN":"辛苦了，瑪卡，現在就交給我們吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"야, 우리 이제 어떡해?","JPN":"ねえ、この後どうするの？","ENG":"Hey, what do we do now?","TWN":"喂，我們現在要怎麼辦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"여기까지 봤을 거 아니야? 설마 민간인 썰고 피의 축제라도 벌이자는 건 아니지?","JPN":"ここまで見たんでしょ？　まさか民間人を斬り倒して血の宴を開きましょうなんて言わないよね？","ENG":"You saw all this, right? You aren't suggesting we butcher civilians and throw a blood feast, are you?","TWN":"妳應該有看到這裡吧？不會是要砍殺平民百姓，舉辦一場血的慶典吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이상해.","JPN":"おかしい。","ENG":"Something's wrong.","TWN":"真奇怪。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"지금 공격 때문이 아니라면, 내가 본 미래는 대체……?","JPN":"今の攻撃のせいじゃないなら、私が見た未来はいったい……？","ENG":"If it's not because of this attack, then what was the future I saw...?","TWN":"如果現在不是因為攻擊，那我看到的未來到底是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"망했다. 맛이 가버렸네.","JPN":"ダメだ。壊れちゃった。","ENG":"Crap. She's gone off the deep end.","TWN":"糟糕，徹底走偏了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"보리스 아저씨, 잠시만.","JPN":"ボリスおじさん、待って。","ENG":"Mr. Boris, wait.","TWN":"布里斯大叔，等一下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"저 마스크 쓴 사람. 그렇게 나쁜 사람은 아닌 것 같아.","JPN":"あのマスクの人、そんなに悪い人じゃないと思う。","ENG":"The one in the mask. I don't think she's that bad.","TWN":"那個戴著口罩的人，好像沒有那麼壞。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"응? 갑자기 무슨 소리냐?","JPN":"うん？　急にどうしたんだ？","ENG":"Hmm? What are you saying all of a sudden?","TWN":"嗯？妳突然在說什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"저 사람. 싸우는 내내 내가 다치지 않도록 힘조절을 했어.","JPN":"あの人、戦ってる間ずっと私が怪我しないように手加減してた。","ENG":"She kept holding back so I wouldn't get hurt.","TWN":"那個人在戰鬥的時候為了不讓我受傷，一直調節力量。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"먼저 공격한 것도 이쪽이었으니, 이야기를 듣는 편이 좋을 것 같아.","JPN":"先に攻撃したのも私のほうだから、話を聞いたほうがいいと思う。","ENG":"We attacked first, so we should probably hear them out.","TWN":"既然是我們先發動攻擊，還是聽聽他們怎麼說會比較好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯哼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"그래. 이야기정도라면 못 들어줄 것도 없지.","JPN":"わかった。話ぐらいなら聞いてやれないこともない。","ENG":"All right. We can at least listen.","TWN":"好，如果只是說個話也沒什麼好不能聽的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"이봐, 너. 시린그라드에 온 목적이 뭐지?","JPN":"おい、お前。シリングラードに来た目的は何だ？","ENG":"You there. Why did you come to Ciringrad?","TWN":"喂，妳來錫林格勒的目的是什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"음… 세계평화?","JPN":"うーん……世界平和のため？","ENG":"Mm... World peace?","TWN":"嗯…世界和平？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"노, 농담 아니거든요? 진짜 세계평화 때문이라고요!","JPN":"じょ、冗談じゃないですってばぁ！　本当に世界平和のためなんです！","ENG":"I-I'm not kidding. It really is for world peace!","TWN":"這、這不是玩笑話，真的是因為世界和平！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 세계평화인지는 모르겠지만, 저쪽은 저쪽 나름의 사정이 있겠지.","JPN":"ああ、世界平和かは知らんが、向こうは向こうなりの事情があるじゃろう。","ENG":"Right. I do not know about world peace, but she has her reasons.","TWN":"好，雖然不知道是不是世界和平，但妳應該有自己的原因吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 넌 아니다. 이 골칫덩어리야.","JPN":"だがお主は違うぞ、この問題児。","ENG":"But not you. You troublemaker.","TWN":"但妳不是，這個麻煩鬼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"아악…! 그만 때려! 지금 이러고 있을 때가 아니라고!","JPN":"ああっ……！　ぶたないでよ！　こうしてる暇ないんだから！","ENG":"Agh...! Stop hitting me! This is not the time!","TWN":"啊啊…！別再打了！現在不是該這樣的時候！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"나오님. 잠시 시간 괜찮으신지요.","JPN":"ナオ様、少しよろしいでしょうか。","ENG":"Miss Nao. Do you have a moment?","TWN":"奈緒，妳有空嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L45_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오, 사나에구나. 무슨 일이더냐?","JPN":"お、早苗ではないか。どうしたのじゃ？","ENG":"Oh, Sanae. What is it?","TWN":"喔，是早苗啊，怎麼回事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"주인어른의 직언을 좇아 고르디우스의 전 대원이 챔버로 향하는 중입니다.","JPN":"社長の言葉に従い、ゴルディウスの全隊員がチェンバーへ向かっています。","ENG":"Per Master's directive, all Gordias Division members are headed to Chamber.","TWN":"哥帝爾斯所有隊員聽從主人的直言，正在前往密室。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"도시관리국에 주인어른의 지인이 계시니, 그분께 합세해 힘을 보태라 하시더군요.","JPN":"都市管理局に社長の知人がいらっしゃるので、その方に加勢するようにと。","ENG":"There is an acquaintance of Master in the City Management. We are to join them and lend support.","TWN":"城市管理局有主人的朋友在，要我和那位合作，助他一臂之力。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"고르디우스 전대 전원이 움직인다고?","JPN":"ゴルディウス戦隊全員が動いたじゃと？","ENG":"The entire Gordias Division is mobilizing?","TWN":"哥帝爾斯戰隊全員採取行動？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이상하군. 구 관리국 전대를 움직일 만한 일이라면 나도 낌새정도는 느꼈을 터인데.","JPN":"おかしいのう。旧管理局戦隊を動かすようなことなら、わしも気配ぐらいは感じとったはず。","ENG":"Strange. If something could move an Old Administration Division, I should have sensed it.","TWN":"真奇怪，如果是舊管理局戰隊會採取行動的事，我至少也會感受到一點苗頭。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"……나오님. 부디 침착히 들으시죠.","JPN":"……ナオ様、落ち着いて聞いてください。","ENG":"...Miss Nao, please remain calm and listen.","TWN":"……奈緒，請妳冷靜點聽我說。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"몇 시간 전, 구 관리국의 전조 프로토콜이 발동되었다고 합니다.","JPN":"数時間前、旧管理局の前兆プロトコルが発動したとのことです。","ENG":"A few hours ago, the Old Administration's Omen Protocol was triggered.","TWN":"幾小時前，舊管理局的前兆協議啟動了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"구, 구 관리국의 전조 프로토콜이라고?","JPN":"きゅ、旧管理局の前兆プロトコルじゃと？","ENG":"Th-the Old Administration's Omen Protocol?","TWN":"舊、舊管理局的前兆協議？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"관리자는, 그 녀석은 무사한가!?","JPN":"管理者は、やつは無事か？","ENG":"The Administrator, is he safe?!","TWN":"管理者呢？那傢伙平安無事嗎！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"주인어른께서는 로터스 관리국의 비호 아래 계시니 염려 마시길.","JPN":"社長はロータス管理局の保護下にいますので、ご心配なく。","ENG":"Not to worry. Master is under the Lotus Administration's protection.","TWN":"主人目前受到洛德斯管理局的庇護，妳不用擔心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제길. 영묘에 얽힌 기운이 불안하다 싶더니, 선조께서 진즉 위험을 알리셨는가…!!","JPN":"くそ、霊廟の気配がどうも不穏だと思ったが、危険を知らせる先祖の意思じゃったか……！","ENG":"Damn it. I felt uneasy about the aura around the tombs. Was that our ancestors warning us...?!","TWN":"該死，我還想說靈廟繚繞的氣息很不安，難道是祖先早就告知有危險了嗎…！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나도 너희들이 있는 곳으로 가겠다! 합류지점은–.","JPN":"わしもお主らのところへ向かう！　合流地点は……","ENG":"I will head to your location as well. The rally point is–","TWN":"我也要去妳們所在的地方！會合地點是–"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 갑자기 지진이라고?","JPN":"な、何じゃ？　急に地震か？","ENG":"W-what? An earthquake?!","TWN":"搞、搞什麼？突然地震？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"사나에! 들리느냐, 사나에?","JPN":"早苗！　聞こえておるか？　早苗！","ENG":"Sanae! Can you hear me, Sanae?","TWN":"早苗！妳有聽到嗎，早苗？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"빌어먹을. 회선이 망가졌나…!!","JPN":"ちくしょう。回線が切れてしまったか……！！","ENG":"Damn it. The comms disconnected...!!","TWN":"該死，線路壞了嗎…！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L20_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"다, 다들 침착해! 우선 병기들 밑으로 몸을 피해라!","JPN":"み、皆落ち着け！　まず兵器の下に身を隠すんだ！","ENG":"E-everyone, stay calm! Get under the machines for cover!","TWN":"大、大家冷靜點！先躲到兵器底下吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"몇 번이나 말했잖아! 얼마 안가 건물이 무너질 거라고!","JPN":"何度も言ったじゃない！　もうすぐ建物が崩れるって！","ENG":"I told you again and again that the building is going to collapse soon!","TWN":"我都說幾次了！建築不久後就會倒塌！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"카운터면 모를까. 이대로면 당신들 전부 개죽음이야!","JPN":"カウンターならまだしも、このままじゃお前たち全員無駄死にするわ！","ENG":"Counters might survive. But at this rate, the rest of you will die for nothing!","TWN":"制裁者不好說，但這樣下去你們全都會白白送死！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어라, 혹시 기회인가?","JPN":"あれ、もしかしてチャンス？","ENG":"Huh, maybe this is our chance?","TWN":"咦？難道這是機會？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"지금이라면 어렵지 않게 빠져나갈 수 있을 것 같은데.","JPN":"今なら簡単に抜け出せそうだけど。","ENG":"Right now we could slip out without much trouble.","TWN":"現在應該能輕易逃脫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"북방합의체 실험의 유일한 장점은 이런 상황에 익숙해진다는 거야.","JPN":"北方合意体の実験の唯一のいいところは、こんな状況に慣れるってことだよね。","ENG":"The only upside to Northern Union experiments is that you get used to situations like this.","TWN":"北方和議會實驗的唯一優點就是習慣這種情況了。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"비명소리는 기껏해야 소음처럼 느껴지고, 절박한 표정을 봐도 아무런 감흥이 없거든.","JPN":"悲鳴なんかちょっとした雑音にしか聞こえなくなるし、人の切羽詰まった顔を見ても動じなくなるもん。","ENG":"Screams sound like mere noise, and desperate faces stir nothing.","TWN":"尖叫聲感覺起來頂多像噪音一樣，就算看到急迫的表情也沒有任何感覺。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"가자, 여기서 이러고 있을 틈 없어.","JPN":"行こう、ここで立ち止まってる場合じゃない。","ENG":"Let's go. We don't have time to stand around.","TWN":"走吧，沒有時間杵在這裡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"뭣…! 여기 있는 사람들은?","JPN":"なっ……！　ここにいる人たちは？","ENG":"W-what...?! What about these people?","TWN":"什麼…！那這裡的人呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭘 이제 와서 착한 척이야? 어쭙잖게 동정하다가 큰일로 번진다는 거 몰라?","JPN":"今更何いい人ぶってるの？　下手に情をかけたら大事になるかもしれないんだよ？","ENG":"Acting all noble now? Half-baked sympathy just makes disasters worse, you know.","TWN":"事到如今還裝什麼善良？妳不知道無謂地同情會鬧出大事嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그 정도는 나도 알아!","JPN":"それぐらい分かってるわよ！","ENG":"I know that much!","TWN":"這我也知道！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"나도 내가 이런 말하는 게 웃기고, 어이없다는 거 알지만…….","JPN":"自分でもこういうことを言うなんておかしいって分かってるけど……","ENG":"I know it sounds laughable and absurd coming from me, but...","TWN":"我也覺得自己這樣說很可笑又令人無奈……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"저 사람들을 놔두고 도망칠 수가 없다고…!!","JPN":"あの人たちを置いて逃げられないのよ……！！","ENG":"I can't run away and leave them...!!","TWN":"但不能丟下那些人逃跑…！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"아직도 선명해. 결단하지 못한 아이들이 실험실에서 어떻게 됐는지.","JPN":"まだ鮮明に浮かぶ。決断できなかった子たちが実験室でどうなったのか。","ENG":"It's still vivid. What happened to the kids who couldn't decide in the lab.","TWN":"我還記得很清楚，那些沒能做出決斷的孩子在實驗室裡怎麼樣了。"},"stage":{"bg":"TRAINING","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"목줄 안에서 쇳조각이 나오는 건 물론, 어떤 애는 잘린 팔을 무기처럼 썼다니까?","JPN":"首輪の内側からくさびが出てくるのなんて普通にあったし、切り落とされた自分の腕を武器のように使ってた子もいたなぁ。","ENG":"When they resisted, shards erupted from the collars and dug into their necks. Some even used severed arms like weapons.","TWN":"不只是項圈裡面會冒出鐵塊，還有孩子把被砍斷的手臂拿來當武器用。"},"stage":{"bg":"TRAINING","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"그걸로 폐쇄된 실험실의 문을 박박 긁는데… 왜 그렇게 미련한 짓을 하나 싶더라.","JPN":"それで閉鎖された実験室のドアを引っ掻きまくって……なんてバカなことをするんだろうって思ったっけ。","ENG":"They scraped the sealed lab door with them... I wondered why they were being so foolish.","TWN":"用那個不停刮著實驗室封閉的門…我還心想他們為什麼要做這麼愚蠢的事。"},"stage":{"bg":"TRAINING","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"정작 그 아이가 죽은 이후, 내 모습도 다를 바 없었지만.","JPN":"あの子が死んだ後は私も似たようなもんだったけどね。","ENG":"After that child died, I was no different.","TWN":"雖然那個孩子死了之後，我的樣子也沒有什麼改變。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"뚫린 외벽 때문에 건물의 균형이 무너지고 있어.","JPN":"外壁がなくなって建物のバランスが崩れている。","ENG":"The blown-out outer wall is throwing the building off balance.","TWN":"因為外牆被打穿，建築正在失去平衡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"보리스 아저씨…!!","JPN":"ボリスおじさん……！！","ENG":"Mr. Boris...!!","TWN":"布里斯大叔…！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"늦었어! 오지 마라, 마브카!!","JPN":"もう遅い！　来るな、マブカ！！","ENG":"It's too late! Don't come, Mavka!!","TWN":"來不及了！別過來，瑪卡！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L18_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"으, 응? 산 건가…?","JPN":"う、うん？　生きているのか……？","ENG":"H-huh? I'm alive...?","TWN":"呃、嗯？活下來了嗎…？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"야, 관음증 변태! 네 능력으로 뭐 보이는 거 없어?","JPN":"覗き魔！　あなたの能力で何か見えないの？","ENG":"Hey, voyeur creep! Do you see anything with that power of yours?","TWN":"喂，偷窺變態！妳能不能用妳的能力看到什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"검은 이터니움을 챙기긴커녕, 이대로는 사람들만 죽는다고!","JPN":"黒いエタニウムどころか、このままじゃ人が死ぬだけだってば！","ENG":"Forget securing the Dark Eternium. At this rate, we're all going to die!","TWN":"別說是拿走黑色永恆之金了，這樣下去所有人都會沒命！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그게 됐으면 이러고 있겠어? 지진이 난 이후로 능력이 더 불안정하단 말이야!","JPN":"できたんならとっくにそうしたさ！　地震が起きてから能力が更に不安定になったのよ！","ENG":"If I could, would I be standing here? My ability has been even unstable since the quake!","TWN":"如果看得到我還會這樣嗎？地震之後能力變得更不穩定了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제길. 히키코모리 시니어가 피만 안 뽑았어도 어떻게든 해보는 건데…!!","JPN":"くそ。引きこもりシニアに血を抜かれてなかったら、なんとかしてみるのに……！！","ENG":"Damn it! If that hermit Senior hadn't drained my blood, I might manage something, but...!!","TWN":"該死，要是宅男Senior沒有抽血，我就能想想辦法…！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START"},{"id":"L30_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"멍 때리고 있지 마라, 마브카!","JPN":"ぼーっとするな、マブカ！","ENG":"Stay sharp, Mavka!","TWN":"不要發呆，瑪卡！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L31_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"우린 신경 쓰지 말고, 너라도 여기서 빠져나가!","JPN":"私たちのことは気にせず、お前だけでもここから逃げろ！","ENG":"Forget us and get yourself out of here!","TWN":"別在意我們，妳自己先脫離這裡！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"……아냐, 보리스 아저씨.","JPN":"……違うの、ボリスおじさん。","ENG":"...No, Mr. Boris.","TWN":"……不，布里斯大叔。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"소리. 들려오고 있어.","JPN":"音。聞こえてくる。","ENG":"The sound. It's getting closer.","TWN":"有聲音傳來。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"뭐?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이건… 헬리콥터 소리?","JPN":"これは……ヘリの音か？","ENG":"Is that... a helicopter?","TWN":"這是…直升機的聲音？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이 소리… 설마…….","JPN":"この音……まさか……","ENG":"That sound... It can't be...","TWN":"這聲音…難道是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"바, 바바 야가!?","JPN":"バ、バーバ・ヤーガ！？","ENG":"B-Baba Yaga?!","TWN":"芭、芭芭雅嘎！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"문득, 고개를 들어 올려다본 전경이 실험실 천장이 아니라는 걸 깨달았을 때.","JPN":"ふと、顔を上げた私の目に映るものが実験室の天上じゃないって気づいた時。","ENG":"The moment I looked up and realized the view was not a lab ceiling,","TWN":"突然間，意識到抬頭仰望的景象不是實驗室天花板的時候。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"내 소리를 듣고 누군가 와줬다는 걸 알았어.","JPN":"私の声を聞いて誰かが来てくれたんだって分かった。","ENG":"I knew someone had heard my voice and come.","TWN":"我知道有人聽到我的聲音後跑來了。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"부질없는 몸부림이 제법 좋은 결과로 이어질 수 있다는 걸, 그때 알았지.","JPN":"儚い足掻きでも、案外いい結果につながることもあるって、その時知ったよ。","ENG":"That was when I learned that futile thrashing can sometimes lead to something good.","TWN":"那時候才明白，無謂的掙扎會帶來很好的結果。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예니카아아아–––!!","JPN":"イェニカあああ───！！","ENG":"YANIKKAAAA–––!!","TWN":"耶妮卡啊啊啊–––！！"},"stage":{"bg":"SKY","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"저, 안 늦었죠?","JPN":"私、間に合いましたよね？","ENG":"I-I'm not late, am I?","TWN":"我沒有來晚吧？"},"stage":{"bg":"SKY","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"SKY","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 몸부림친 후 보게 된 하늘은.","JPN":"そうやって足掻いた後に目にした空は。","ENG":"After struggling like that,","TWN":"這樣掙扎之後看見的天空，"},"stage":{"bg":"SKY","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"내가 생각했던 것보다, 제법 푸르더라.","JPN":"思った以上に、青かった。","ENG":"the sky I saw was much bluer than I had imagined.","TWN":"比我想像中的更加蔚藍。"},"stage":{"bg":"SKY","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에휴.","JPN":"はあ。","ENG":"Whew.","TWN":"唉唷，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"살다 살다…… 합의체 사람이 반가운 날이 오네.","JPN":"私の人生で……合意体の人が来て嬉しいと思う日がくるとはね。","ENG":"Never thought I'd see the day when... I'm glad to see a Northern Union person.","TWN":"活到現在……居然會有一天歡迎和議會的人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};